prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?prop (COUNT(*) as ?count) WHERE {
  {
    ?elem bbo:name "Process provisioning" .
    ?elem ?prop ?value .
  }
  UNION
  {
    ?elem bbo:name "Operations provisioning" .
    ?elem ?prop ?value .
  }
}
GROUP BY ?prop
ORDER BY DESC(?count)
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?intermediateTaskName WHERE {
  ?startTask bbo:name "Process provisioning" .
  ?endTask bbo:name "Operations provisioning" .

  ?flow1 a bbo:SequenceFlow ;
         bbo:has_sourceRef ?startTask ;
         bbo:has_targetRef ?intermediateTask .

  ?flow2 a bbo:SequenceFlow ;
         bbo:has_sourceRef ?intermediateTask ;
         bbo:has_targetRef ?endTask .

  ?intermediateTask bbo:name ?intermediateTaskName .
}
